(async () => {
      const workspace = await prisma.project.findUniqueOrThrow({
        where: {
          id: workspaceId,
        },
        select: {
          name: true,
          slug: true,
          users: {
            select: {
              user: {
                select: { email: true },
              },
            },
            where: {
              userId,
            },
          },
          installedIntegrations: {
            where: {
              integrationId,
            },
            select: {
              integration: {
                select: {
                  name: true,
                  slug: true,
                },
              },
            },
          },
        },
      });

      const email =
        workspace.users.length > 0 ? workspace.users[0].user.email : null;
      const integration =
        workspace.installedIntegrations.length > 0
          ? workspace.installedIntegrations[0].integration
          : null;

      if (email && integration) {
        await sendEmail({
          to: email!,
          subject: `The "${integration.name}" integration has been added to your workspace`,
          react: IntegrationInstalled({
            email: email!,
            workspace: {
              name: workspace.name,
              slug: workspace.slug,
            },
            integration: {
              name: integration.name,
              slug: integration.slug,
            },
          }),
        });
      }
    })
